import { Note, StrudelConfig, Track } from '../types';
import { INSTRUMENT_MAPPING } from '../constants';

// Helper for rounding
const round = (num: number, precision: number) => {
  const factor = Math.pow(10, precision);
  return Math.round(num * factor) / factor;
};

export class StrudelNotation {
  private config: StrudelConfig;

  constructor(config: StrudelConfig) {
    this.config = config;
  }

  public generate(tracks: Track[]): string {
    // 1. Calculate Global Song Duration to pad all tracks
    let maxDuration = tracks.reduce((max, t) => {
        const trackMax = t.notes.reduce((m, n) => Math.max(m, n.noteOff), 0);
        return Math.max(max, trackMax);
    }, 0);

    const barDur = (60 / this.config.sourceBpm) * this.config.timeSignature.numerator;
    if (maxDuration === 0) maxDuration = barDur;

    // 2. Generate CPS setup
    let cpsFormula = "";
    if (this.config.cycleUnit === 'bar') {
        const numerator = this.config.timeSignature.numerator || 4;
        cpsFormula = `${this.config.bpm} / 60 / ${numerator}`;
    } else {
        cpsFormula = `${this.config.bpm} / 60`;
    }

    let output = `// Generated by Strudel MIDI Converter\n// Source BPM: ${this.config.sourceBpm} | Playback BPM: ${this.config.bpm}\nsetcps(${cpsFormula});\n\n`;

    tracks.forEach(track => {
      if (track.hidden) return;
      if (!track.notes.length) return;

      output += this.processTrack(track, maxDuration);
      output += '\n';
    });

    return output;
  }

  private processTrack(track: Track, globalMaxDuration: number): string {
    const notes = this.prepareNotes(track.notes);

    // Determine sound
    let sound = this.config.globalSound;
    if (this.config.soundMode === 'instrumentMapping') {
      sound = track.sound || INSTRUMENT_MAPPING[track.instrumentFamily?.toLowerCase() || ''] || 'triangle';
    }

    if (this.config.outputStyle === 'melody+harmony') {
      const { melody, harmony } = this.splitMelodyHarmony(notes);
      let trackOutput = "";

      if (melody.length > 0) {
        const melodyCode = this.renderSequence(melody, globalMaxDuration);
        trackOutput += `$${this.formatTrackName(track.name)}_MELODY: \`<\n${melodyCode}\n>\`\n  .as("${this.getAsString()}")\n  .sound("${sound}");\n\n`;
      }

      if (harmony.length > 0) {
        const harmonyCode = this.renderSequence(harmony, globalMaxDuration);
        trackOutput += `$${this.formatTrackName(track.name)}_HARMONY: \`<\n${harmonyCode}\n>\`\n  .as("${this.getAsString()}")\n  .sound("${sound}");\n\n`;
      }
      return trackOutput;
    }

    return `// Unknown output style`;
  }

  private formatTrackName(name: string): string {
    return name.toUpperCase()
      .replace(/[^A-Z0-9]/g, '_')
      .replace(/_+/g, '_')
      .replace(/^_/, '')
      .replace(/_$/, '');
  }

  private getAsString(): string {
    let s = this.config.notationType === 'absolute' ? "note" : "n";
    if (this.config.includeVelocity) s += ":velocity";
    return s;
  }

  private prepareNotes(rawNotes: Note[]): Note[] {
    let notes = [...rawNotes].sort((a, b) => a.noteOn - b.noteOn);

    if (this.config.isQuantized) {
      const beatDuration = 60 / this.config.sourceBpm; 
      const gridUnit = beatDuration / 4; 
      const strength = this.config.quantizationStrength / 100;

      notes = notes.map(n => {
        const nearestOn = Math.round(n.noteOn / gridUnit) * gridUnit;
        const diffOn = nearestOn - n.noteOn;
        let newOn = n.noteOn;

        if (Math.abs(diffOn) * 1000 <= this.config.quantizationThreshold) {
           newOn = n.noteOn + (diffOn * strength);
        }

        const dur = n.noteOff - n.noteOn;
        const nearestDur = Math.round(dur / gridUnit) * gridUnit;
        const diffDur = nearestDur - dur;
        let newDur = dur;

        if (Math.abs(diffDur) * 1000 <= this.config.quantizationThreshold) {
           newDur = dur + (diffDur * strength);
        }

        if (newDur < gridUnit * 0.1) newDur = gridUnit;

        return { ...n, noteOn: newOn, noteOff: newOn + newDur };
      });
    }

    return notes;
  }

  private splitMelodyHarmony(notes: Note[]): { melody: Note[], harmony: Note[] } {
    const melody: Note[] = [];
    const harmony: Note[] = [];
    let lastEnd = 0;

    const sorted = [...notes].sort((a, b) => a.noteOn - b.noteOn);

    sorted.forEach(note => {
      if (note.noteOn >= lastEnd - 0.01) {
        melody.push(note);
        lastEnd = note.noteOff;
      } else {
        harmony.push(note);
      }
    });

    return { melody, harmony };
  }

  private getCycleDuration(): number {
    const beatDur = 60 / this.config.sourceBpm; 
    if (this.config.cycleUnit === 'beat') return beatDur;
    return beatDur * (this.config.timeSignature.numerator || 4);
  }

  private renderSequence(notes: Note[], totalDuration: number): string {
    const cycleDur = this.getCycleDuration();
    const measureDur = (60 / this.config.sourceBpm) * (this.config.timeSignature.numerator || 4);

    const measures: Note[][] = [];
    notes.forEach(note => {
      const mIdx = Math.floor((note.noteOn + 0.001) / measureDur);
      if (!measures[mIdx]) measures[mIdx] = [];
      measures[mIdx].push(note);
    });

    const totalMeasures = Math.max(1, Math.ceil(totalDuration / measureDur));
    const rawTokens: string[] = [];

    for (let i = 0; i < totalMeasures; i++) {
      const measureNotes = measures[i] || [];
      const measureStart = i * measureDur;

      let measureString = "";
      if (this.config.timingStyle === 'relativeDivision') {
        measureString = this.renderMeasureSubdivision(measureNotes, measureStart, measureDur, cycleDur);
      } else {
        measureString = this.renderMeasureAbsolute(measureNotes, measureStart, measureDur, cycleDur);
      }

      if (measureString) rawTokens.push(measureString);
    }

    // Merge consecutive rests
    const mergedTokens: string[] = [];

    const isRest = (token: string) => {
      const t = token.trim();
      if (/[A-G]/.test(t) || /{/.test(t) || /\[/.test(t)) return false; 
      // Treat `~` or `~@2` as rest
      return /^~(@[\d\.]+)?$/.test(t);
    };

    const getRestDuration = (token: string): number => {
       if (token === '~') return 1;
       const parts = token.split('@');
       if (parts.length === 2) return parseFloat(parts[1]);
       return 1;
    };

    const createRestToken = (duration: number): string => {
       const d = round(duration, this.config.durationPrecision);
       if (d === 1) return `~`;
       return `~@${d}`;
    };

    for (const token of rawTokens) {
      if (!token.trim()) continue;

      if (isRest(token)) {
        const lastIdx = mergedTokens.length - 1;
        if (lastIdx >= 0 && isRest(mergedTokens[lastIdx])) {
          const prevDur = getRestDuration(mergedTokens[lastIdx]);
          const currDur = getRestDuration(token);
          mergedTokens[lastIdx] = createRestToken(prevDur + currDur);
        } else {
          mergedTokens.push(token);
        }
      } else {
        mergedTokens.push(token);
      }
    }

    let outputLines: string[] = [];
    let currentLine = "";
    let itemsInLine = 0;

    for (const token of mergedTokens) {
      currentLine += token + " ";
      itemsInLine++;

      if (itemsInLine >= this.config.measuresPerLine) {
        outputLines.push(currentLine.trim());
        currentLine = "";
        itemsInLine = 0;
      }
    }

    if (currentLine.trim()) outputLines.push(currentLine.trim());

    return outputLines.join('\n');
  }

  private formatNoteVal(note: Note, cycleDur: number, durOverride?: number): string {
    const val = this.config.notationType === 'absolute' ? note.note : (note.midi - 60).toString(); 

    let suffix = "";
    if (this.config.includeVelocity) {
      suffix += `:${round(note.velocity, 2)}`;
    }

    if (this.config.timingStyle === 'absoluteDuration') {
      const d = durOverride !== undefined ? durOverride : (note.noteOff - note.noteOn);
      const cycles = d / cycleDur;
      // Strip @1 if exactly 1
      if (Math.abs(cycles - 1) < 0.001) return `${val}${suffix}`;
      return `${val}${suffix}@${round(cycles, this.config.durationPrecision)}`;
    } else {
       return `${val}${suffix}`;
    }
  }

  private renderMeasureAbsolute(notes: Note[], measureStart: number, measureDur: number, cycleDur: number): string {
    const EPSILON = 0.01;
    const durVal = measureDur / cycleDur;

    if (notes.length === 0) {
       return durVal === 1 ? `~` : `~@${round(durVal, this.config.durationPrecision)}`;
    }

    let cursor = measureStart;
    let output = "";

    const sorted = [...notes].sort((a,b) => a.noteOn - b.noteOn);

    for (let i = 0; i < sorted.length; i++) {
      const note = sorted[i];

      if (note.noteOn > cursor + EPSILON) {
        const gap = note.noteOn - cursor;
        const gapCycles = gap / cycleDur;
        if (gapCycles > 0.001) {
            const r = round(gapCycles, this.config.durationPrecision);
            output += (r === 1 ? `~ ` : `~@${r} `);
        }
        cursor += gap;
      } else {
        cursor = Math.max(cursor, note.noteOn);
      }

      const chordNotes = [note];
      let j = i + 1;
      while(j < sorted.length && Math.abs(sorted[j].noteOn - note.noteOn) < EPSILON) {
        chordNotes.push(sorted[j]);
        j++;
      }
      i = j - 1;

      if (chordNotes.length > 1) {
         const maxEnd = Math.max(...chordNotes.map(n => n.noteOff));
         const dur = maxEnd - note.noteOn;
         const noteStrs = chordNotes.map(n => this.formatNoteVal(n, cycleDur, 0)); 
         const cycles = dur / cycleDur;
         const r = round(cycles, this.config.durationPrecision);
         const suffix = r === 1 ? "" : `@${r}`;
         output += `{${noteStrs.join(', ')}}${suffix} `;
         cursor = maxEnd;
      } else {
         output += `${this.formatNoteVal(note, cycleDur)} `;
         cursor = note.noteOff;
      }
    }

    if (cursor < measureStart + measureDur - EPSILON) {
      const rem = (measureStart + measureDur) - cursor;
      const remCycles = rem / cycleDur;
      if (remCycles > 0.001) {
          const r = round(remCycles, this.config.durationPrecision);
          output += (r === 1 ? `~` : `~@${r}`);
      }
    }

    return output.trim();
  }

  private renderMeasureSubdivision(notes: Note[], measureStart: number, measureDur: number, cycleDur: number): string {
    const cycles = measureDur / cycleDur;
    const cyclesRounded = round(cycles, 2);

    // If empty measure, return simple rest
    if (notes.length === 0) {
        return cyclesRounded === 1 ? `~` : `~@${cyclesRounded}`;
    }

    // Dynamic Grid Detection
    // Try to find the best grid size (subdivisions) that matches note start times
    const resolutions = [1, 2, 3, 4, 6, 8, 12, 16, 24, 32];
    let bestRes = 16;

    for (const res of resolutions) {
        let isFit = true;
        for (const note of notes) {
            const relStart = (note.noteOn - measureStart) / measureDur;
            const pos = relStart * res;
            // Check if note start aligns with grid line
            if (Math.abs(pos - Math.round(pos)) > 0.05) { 
                isFit = false;
                break;
            }
        }
        if (isFit) {
            bestRes = res;
            break; // Prefer smallest functional grid
        }
    }

    const subdivs = bestRes; 
    const gridDuration = measureDur / subdivs; 
    const grid: string[] = new Array(subdivs).fill("~");

    notes.forEach(note => {
       const relStart = note.noteOn - measureStart;
       const startIndex = Math.round(relStart / gridDuration);

       const dur = note.noteOff - note.noteOn;
       let slots = Math.round(dur / gridDuration);
       if (slots < 1) slots = 1;

       if (startIndex >= 0 && startIndex < subdivs) {
         // Clean note value (remove duration if present from formatNoteVal)
         const val = this.formatNoteVal(note, cycleDur, 0).replace(/@.*/, ''); 
         grid[startIndex] = val;

         // Sustain logic
         for(let k=1; k<slots && (startIndex+k) < subdivs; k++) {
            if (grid[startIndex+k] === "~") { 
                grid[startIndex+k] = "_";
            }
         }
       }
    });

    const content = grid.join(" ");

    // Handle @1 removal
    const suffix = cyclesRounded === 1 ? "" : `@${cyclesRounded}`;

    return `[${content}]${suffix}`;
  }
}

To address the issues with the subdivision syntax and formatting, I will significantly refactor `services/StrudelNotation.ts`.

### Key Changes
1.  **Smart Windowing (Measure Accumulation)**: Instead of slicing tracks into rigid measures, the generator now iterates through time using a "Smart Window". It collects notes for a standard measure duration, but if a note extends beyond the measure boundary, it **extends the window** to include the full note (snapping to the next measure). This prevents notes from being cut off and fulfills the "accumulate notes" requirement.
2.  **Improved Subdivision Logic**:
    *   **Tuplet Detection**: The grid resolution logic now prioritizes the number of notes in the window (e.g., 12 notes -> 12 steps), which fixes the "1/12th note" issue where unexpected rests were appearing.
    *   **Dynamic Resolution**: It searches for the best grid fit up to 64 steps.
    *   **Gap Filling**: Tiny gaps between notes (micro-jitter) are automatically sustained `_` or ignored to prevent unwanted rests `~` in the output.
3.  **Clean Output**:
    *   **Strip `@1`**: Durations of exactly 1 cycle (e.g., `[ ... ]@1`) now have the `@1` suffix stripped.
    *   **Simplified Rests**: Consecutive rests are merged, and unnecessary subdivision rests are minimized.
    *   **Formatting**: Melodies are kept on appropriate lines based on the accumulated windows.

