  private getCycleDuration(): number {
    const beatDur = 60 / this.config.sourceBpm; 
    if (this.config.cycleUnit === 'beat') return beatDur;
    return beatDur * (this.config.timeSignature.numerator || 4);
  }

  private renderSequence(notes: Note[], totalDuration: number): string {
    const cycleDur = this.getCycleDuration();
    const measureDur = (60 / this.config.sourceBpm) * (this.config.timeSignature.numerator || 4);

    const tokens: string[] = [];
    let cursor = 0;
    const EPSILON = 0.01;

    // Use a smart window that accumulates notes until a logical break (measure boundary)
    // but expands if a note crosses the boundary.
    while (cursor < totalDuration - EPSILON) {
        // 1. Check for gap (rest)
        const nextNotes = notes.filter(n => n.noteOn >= cursor - EPSILON).sort((a,b) => a.noteOn - b.noteOn);

        if (nextNotes.length === 0) {
            // No more notes, pad rest to end
            const restDur = totalDuration - cursor;
            tokens.push(this.createRestToken(restDur, cycleDur));
            break;
        }

        const nextNote = nextNotes[0];
        if (nextNote.noteOn > cursor + EPSILON) {
            const gap = nextNote.noteOn - cursor;
            tokens.push(this.createRestToken(gap, cycleDur));
            cursor = nextNote.noteOn;
        }

        // 2. Define Block Window
        // Start with 1 measure width
        let blockEnd = cursor + measureDur;

        // Find notes that START in this standard window
        let blockNotes = notes.filter(n => n.noteOn >= cursor - EPSILON && n.noteOn < blockEnd - EPSILON);

        // Check if any note in this block extends BEYOND blockEnd
        // If so, extend blockEnd to accommodate it (snap to next measure)
        if (blockNotes.length > 0) {
            const maxEnd = Math.max(...blockNotes.map(n => n.noteOff));
            if (maxEnd > blockEnd + EPSILON) {
                // Snap to nearest measure containing maxEnd
                blockEnd = Math.ceil((maxEnd + EPSILON) / measureDur) * measureDur;
                // Re-fetch notes for expanded window
                blockNotes = notes.filter(n => n.noteOn >= cursor - EPSILON && n.noteOn < blockEnd - EPSILON);
            }
        }

        const blockDur = blockEnd - cursor;

        // 3. Render Block
        let blockString = "";
        if (this.config.timingStyle === 'relativeDivision') {
             blockString = this.renderMeasureSubdivision(blockNotes, cursor, blockDur, cycleDur);
        } else {
             // For Absolute, we usually just list notes, but we can group them by lines based on this block
             blockString = this.renderMeasureAbsolute(blockNotes, cursor, blockDur, cycleDur);
        }

        if (blockString) tokens.push(blockString);
        cursor = blockEnd;
    }

    // Merge consecutive rests logic
    const mergedTokens: string[] = [];
    for (const token of tokens) {
      if (!token.trim()) continue;
      if (this.isRest(token)) {
        const lastIdx = mergedTokens.length - 1;
        if (lastIdx >= 0 && this.isRest(mergedTokens[lastIdx])) {
          const prevDur = this.getRestDuration(mergedTokens[lastIdx]);
          const currDur = this.getRestDuration(token);
          mergedTokens[lastIdx] = this.createRestToken((prevDur + currDur) * cycleDur, cycleDur); // convert back to seconds for helper
        } else {
          mergedTokens.push(token);
        }
      } else {
        mergedTokens.push(token);
      }
    }

    // Format output lines
    let outputLines: string[] = [];
    let currentLine = "";
    // If subdivision, each token is likely a measure-sized block, so 1 per line is good
    // If absolute, tokens are per note? No, renderMeasureAbsolute returns a block string
    // So 1 block per line is usually safe if blocks are measures

    // Respect measuresPerLine config
    let itemsInLine = 0;
    const itemsPerLine = this.config.measuresPerLine; 

    for (const token of mergedTokens) {
      currentLine += token + " ";
      itemsInLine++;
      if (itemsInLine >= itemsPerLine) {
        outputLines.push(currentLine.trim());
        currentLine = "";
        itemsInLine = 0;
      }
    }
    if (currentLine.trim()) outputLines.push(currentLine.trim());

    return outputLines.join('\n');
  }

  // --- Helpers ---

  private isRest(token: string): boolean {
    const t = token.trim();
    if (/[A-G]/.test(t) || /{/.test(t) || /[0-9]/.test(t.split('@')[0])) {
         // If it contains note data like C4 or 60
         if(t.startsWith('[~]') || t.startsWith('~')) return true;
         return false;
    }
    return /^~(@[\d\.]+)?$/.test(t) || /^\[~\](@[\d\.]+)?$/.test(t);
  }

  private getRestDuration(token: string): number {
     const parts = token.split('@');
     if (parts.length === 2) return parseFloat(parts[1]);
     return 1;
  }

  private createRestToken(durationSeconds: number, cycleDur: number): string {
       const cycles = durationSeconds / cycleDur;
       const r = round(cycles, this.config.durationPrecision);
       const suffix = r === 1 ? "" : `@${r}`;

       if (this.config.timingStyle === 'relativeDivision') {
         return `[~]${suffix}`;
       }
       return `~${suffix}`;
  }


  private formatNoteVal(note: Note, cycleDur: number, durOverride?: number): string {
    const val = this.config.notationType === 'absolute' ? note.note : (note.midi - 60).toString(); 

    let suffix = "";
    if (this.config.includeVelocity) {
      suffix += `:${round(note.velocity, 2)}`;
    }

    if (this.config.timingStyle === 'absoluteDuration') {
      const d = durOverride !== undefined ? durOverride : (note.noteOff - note.noteOn);
      const cycles = d / cycleDur;
      if (Math.abs(cycles - 1) < 0.001) return `${val}${suffix}`;
      return `${val}${suffix}@${round(cycles, this.config.durationPrecision)}`;
    } else {
       return `${val}${suffix}`;
    }
  }

  private renderMeasureAbsolute(notes: Note[], measureStart: number, measureDur: number, cycleDur: number): string {
    const EPSILON = 0.01;
    // ... (Absolute logic remains mostly similar but used within window)

    if (notes.length === 0) return this.createRestToken(measureDur, cycleDur);

    let cursor = measureStart;
    let output = "";

    const sorted = [...notes].sort((a,b) => a.noteOn - b.noteOn);

    for (let i = 0; i < sorted.length; i++) {
      const note = sorted[i];
      if (note.noteOn > cursor + EPSILON) {
        const gap = note.noteOn - cursor;
        if (gap > EPSILON) {
             output += `${this.createRestToken(gap, cycleDur)} `;
        }
        cursor += gap;
      } else {
        cursor = Math.max(cursor, note.noteOn);
      }

      const chordNotes = [note];
      let j = i + 1;
      while(j < sorted.length && Math.abs(sorted[j].noteOn - note.noteOn) < EPSILON) {
        chordNotes.push(sorted[j]);
        j++;
      }
      i = j - 1;

      if (chordNotes.length > 1) {
         const maxEnd = Math.max(...chordNotes.map(n => n.noteOff));
         const dur = maxEnd - note.noteOn;
         const noteStrs = chordNotes.map(n => this.formatNoteVal(n, cycleDur, 0));
         const cycles = dur / cycleDur;
         const suffix = Math.abs(cycles - 1) < 0.001 ? "" : `@${round(cycles, this.config.durationPrecision)}`;
         output += `{${noteStrs.join(', ')}}${suffix} `;
         cursor = maxEnd;
      } else {
         output += `${this.formatNoteVal(note, cycleDur)} `;
         cursor = note.noteOff;
      }
    }

    // Check if remaining space in this block needs filling (it might be part of the flow)
    // The smart window ensures we account for this.
    if (cursor < measureStart + measureDur - EPSILON) {
        const rem = (measureStart + measureDur) - cursor;
        output += this.createRestToken(rem, cycleDur);
    }

    return output.trim();
  }

  private renderMeasureSubdivision(notes: Note[], measureStart: number, measureDur: number, cycleDur: number): string {
    const cycles = measureDur / cycleDur;
    const cyclesRounded = round(cycles, 4);

    if (notes.length === 0) {
        const suffix = cyclesRounded === 1 ? "" : `@${cyclesRounded}`;
        return `[~]${suffix}`;
    }

    // 1. Dynamic Grid Detection
    // Check if notes length is a perfect fit (e.g. 12 notes -> 12 grid)
    // This is often true for generated patterns or tuplets
    const possibleResolutions = [notes.length, 1, 2, 3, 4, 6, 8, 12, 16, 24, 32, 48, 64];
    // Remove duplicates and 0
    const resolutions = [...new Set(possibleResolutions)].filter(r => r > 0).sort((a,b) => a-b);

    let bestRes = 16;
    let found = false;

    for (const res of resolutions) {
        let isFit = true;
        for (const note of notes) {
            const relStart = (note.noteOn - measureStart) / measureDur;
            const pos = relStart * res;
            // Tolerance: 5% of a step
            if (Math.abs(pos - Math.round(pos)) > 0.05) { 
                isFit = false;
                break;
            }
        }
        if (isFit) {
            bestRes = res;
            found = true;
            break; 
        }
    }

    // Fallback if no perfect grid found: default to high res to capture details
    if (!found) bestRes = 32;

    const subdivs = bestRes; 
    const gridDuration = measureDur / subdivs; 
    const grid: string[] = new Array(subdivs).fill("~");

    notes.forEach(note => {
       const relStart = note.noteOn - measureStart;
       const startIndex = Math.round(relStart / gridDuration);

       const dur = note.noteOff - note.noteOn;
       let slots = Math.round(dur / gridDuration);
       if (slots < 1) slots = 1;

       if (startIndex >= 0 && startIndex < subdivs) {
         const val = this.formatNoteVal(note, cycleDur, 0).replace(/@.*/, ''); 
         grid[startIndex] = val;

         // Sustain logic: Fill subsequent slots with '_'
         // NOTE: Only if those slots are currently empty (don't overwrite chords if overlap logic failed)
         for(let k=1; k<slots && (startIndex+k) < subdivs; k++) {
            if (grid[startIndex+k] === "~") { 
                grid[startIndex+k] = "_";
            }
         }
       }
    });

    // Post-process grid:
    // 1. Simplify: If we have gaps that are just micro-jitter, we might want to fill them?
    // Current approach: We trust the grid calculation. 
    // If the grid has `A ~ B`, it means A ended before B started by > 1 grid unit.
    // If bestRes was chosen correctly based on start times, gaps should only appear if they are real.

    // 2. Reduce: If all even slots are notes/rests and odd slots are `_` (sustain) or `~` (rest extension), 
    // we could halve the resolution. (Simplification - maybe overly complex for now).

    const content = grid.join(" ");

    // Clean up @1
    const suffix = cyclesRounded === 1 ? "" : `@${cyclesRounded}`;

    return `[${content}]${suffix}`;
  }
}
